+        // SYS_unlinkat = 263, AT_FDCWD = -100, flags = 0
+        let ret = unsafe { syscall3(263, AT_FDCWD as usize, path_buf.as_ptr() as usize, 0) };
+        assert!(
+            syscall_result(ret).is_ok(),
+            "unlinkat should succeed for cleanup"
+        );
+    }
